import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import { useFormik } from "formik";
import { Select, Button, Input } from "antd";
import Dropzone from "react-dropzone";
import { 
  Plus, 
  Trash2, 
  ShieldCheck, 
  Upload, 
  ChevronLeft, 
  Activity, 
  ShoppingBag,
  Info,
  Save,
  Trash
} from "lucide-react";
import { uploadImg, delImg } from "../../features/upload/uploadSlice";
import { getProducts } from "../../features/product/productSlice";
import { 
  createHealthAdvice, 
  getAHealthAdvice, 
  resetState, 
  updateHealthAdvice 
} from "../../features/healthAdvice/healthAdviceSlice";

const AddHealthAdvice = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const location = useLocation();
    const getAdviceId = location.pathname.split("/")[3];

    const [keySymptoms, setKeySymptoms] = useState([]);
    const [image, setImage] = useState(null);

    const productState = useSelector((state) => state.product.products || []);
    const { isSuccess, isError, isLoading, createdAdvice, updatedAdvice, singleAdvice } = useSelector((state) => state.healthAdvice);

    useEffect(() => {
        dispatch(getProducts());
        if (getAdviceId) {
            dispatch(getAHealthAdvice(getAdviceId));
        } else {
            dispatch(resetState());
        }
    }, [dispatch, getAdviceId]);

    useEffect(() => {
        if (getAdviceId && singleAdvice) {
            formik.setValues({
                conditionName: singleAdvice.conditionName || "",
                healthAdvice: singleAdvice.healthAdvice || "",
                products: singleAdvice.products?.map(p => p._id) || [],
                image: singleAdvice.image || null,
            });
            setKeySymptoms(singleAdvice.keySymptoms || []);
            setImage(singleAdvice.image || null);
        }
    }, [singleAdvice, getAdviceId]);

    useEffect(() => {
        if (isSuccess && createdAdvice) {
            toast.success("Medical Protocol Synchronized!");
            navigate("../health-advice");
        }
        if (isSuccess && updatedAdvice) {
            toast.success("Medical Protocol Updated!");
            navigate("../health-advice");
        }
        if (isError) {
            toast.error("Failed to synchronize protocol. Check consistency.");
        }
    }, [isSuccess, isError, isLoading]);

    const formik = useFormik({
        initialValues: {
            conditionName: "",
            healthAdvice: "",
            products: [],
            image: null,
        },
        onSubmit: (values) => {
            const adviceData = {
                ...values,
                keySymptoms,
                image: image ? {
                    public_id: image.public_id,
                    url: image.url || image.secure_url,
                    secure_url: image.secure_url || image.url,
                } : null,
            };
            if (getAdviceId) {
                dispatch(updateHealthAdvice({ id: getAdviceId, adviceData }));
            } else {
                dispatch(createHealthAdvice(adviceData));
            }
        },
    });

    const addSymptom = (e) => {
        if (e.key === 'Enter' && e.target.value) {
            e.preventDefault();
            setKeySymptoms([...keySymptoms, e.target.value]);
            e.target.value = '';
        }
    };

    const removeSymptom = (idx) => {
        setKeySymptoms(keySymptoms.filter((_, i) => i !== idx));
    };

    const handleImageUpload = (files) => {
        dispatch(uploadImg(files)).then((res) => {
            setImage(res.payload[0]);
        });
    };

    const handleImageDelete = (publicId) => {
        dispatch(delImg(publicId)).then(() => {
            setImage(null);
        });
    };

    return (
        <div className="pb-20 animate-in fade-in slide-in-from-bottom-6 duration-700">
            {/* Nav Header */}
            <div className="flex items-center justify-between mb-12">
                <div className="flex items-center gap-6">
                    <button 
                        onClick={() => navigate(-1)}
                        className="w-12 h-12 flex items-center justify-center rounded-2xl bg-white border border-slate-100 text-slate-400 hover:text-blue-600 shadow-sm transition-all"
                    >
                        <ChevronLeft size={24} />
                    </button>
                    <div>
                        <h1 className="text-[32px] font-black text-slate-900 tracking-tighter leading-none">
                            {getAdviceId ? "Edit Protocol" : "New Medical Protocol"}
                        </h1>
                        <p className="text-[14px] text-slate-400 font-bold mt-1 uppercase tracking-widest italic">Clinical Indexing System</p>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                     <Button 
                        onClick={() => navigate(-1)}
                        className="h-14 px-8 rounded-2xl border-slate-200 text-slate-500 font-black uppercase text-[12px] tracking-widest"
                     >
                        Cancel
                     </Button>
                     <button 
                        type="button"
                        onClick={formik.handleSubmit}
                        disabled={isLoading}
                        className="h-14 px-10 rounded-2xl flex items-center gap-2 justify-center bg-slate-900 text-white border-none font-black uppercase text-[12px] tracking-[0.2em] shadow-xl shadow-slate-900/20 hover:bg-slate-800 hover:text-white cursor-pointer transition-all disabled:opacity-50"
                     >
                        <Save size={18} /> {isLoading ? "Working..." : getAdviceId ? "Update Protocol" : "Synchronize Protocol"}
                     </button>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                {/* Main Content */}
                <div className="lg:col-span-8 space-y-8">
                    <div className="enterprise-card p-10 space-y-10">
                        <div className="space-y-6">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Clinical Information</label>
                            <div className="space-y-4">
                                <Input 
                                    name="conditionName"
                                    placeholder="Condition Name (e.g. Chronic Skin Dryness)"
                                    className="h-16 px-6 bg-slate-50/50 border-slate-100 rounded-2xl text-[17px] font-black tracking-tight"
                                    value={formik.values.conditionName}
                                    onChange={formik.handleChange}
                                />
                                <div className="space-y-4">
                                    <label className="text-[13px] font-black text-slate-600">Protocol Details / Clinical Guidance</label>
                                    <Input.TextArea 
                                        name="healthAdvice"
                                        rows={12}
                                        placeholder="Enter expert-vetted lifestyle advice, treatment plans, and clinical notes..."
                                        className="p-6 bg-slate-50/50 border-slate-100 rounded-[32px] text-[15px] font-medium leading-relaxed"
                                        value={formik.values.healthAdvice}
                                        onChange={formik.handleChange}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="space-y-6">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Indicator Matrix (Symptoms)</label>
                            <div className="flex flex-wrap gap-3">
                                {keySymptoms.map((s, i) => (
                                    <div key={i} className="flex items-center gap-2 pl-4 pr-2 py-2 bg-teal-50 border border-teal-100 rounded-xl">
                                        <span className="text-[13px] font-black text-teal-700">{s}</span>
                                        <button 
                                            onClick={() => removeSymptom(i)}
                                            className="w-6 h-6 flex items-center justify-center rounded-lg bg-teal-100 text-teal-600 hover:bg-rose-500 hover:text-white transition-all"
                                        >
                                            <Trash2 size={12} />
                                        </button>
                                    </div>
                                ))}
                                <Input 
                                    placeholder="Type symptom and press Enter..."
                                    className="h-12 w-64 px-4 bg-white border-dashed border-slate-200 rounded-xl text-[13px] font-bold"
                                    onKeyDown={addSymptom}
                                />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Sidebar */}
                <div className="lg:col-span-4 space-y-8">
                    {/* Image Hub */}
                    <div className="enterprise-card p-10 space-y-6">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Diagnostic Image</label>
                        {image ? (
                            <div className="relative group rounded-3xl overflow-hidden border-2 border-slate-100 shadow-inner h-64">
                                <img src={image.secure_url || image.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                                <div className="absolute inset-0 bg-slate-900/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                    <Button 
                                        onClick={() => handleImageDelete(image.public_id)}
                                        className="h-12 px-6 rounded-xl bg-white/10 hover:bg-rose-500 text-white border-white/20 font-black uppercase text-[11px]"
                                    >
                                        Delete Frame
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <Dropzone onDrop={handleImageUpload} accept={{"image/*": []}} multiple={false}>
                                {({getRootProps, getInputProps}) => (
                                    <div {...getRootProps()} className="border-4 border-dashed border-slate-100 rounded-[32px] p-12 text-center hover:bg-slate-50 hover:border-blue-200 transition-all group cursor-pointer">
                                        <input {...getInputProps()} />
                                        <div className="w-16 h-16 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center mx-auto mb-6 group-hover:scale-110 transition-transform">
                                            <Upload size={32} />
                                        </div>
                                        <p className="text-[14px] font-black text-slate-900 mb-1">Upload Protocol Image</p>
                                        <p className="text-[11px] text-slate-400 font-bold uppercase tracking-widest">Medical grade resolution</p>
                                    </div>
                                )}
                            </Dropzone>
                        )}
                    </div>

                    {/* Product Linkage */}
                    <div className="enterprise-card p-10 space-y-6">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em]">Fulfillment Protocol (Linked Products)</label>
                        <Select 
                            mode="multiple"
                            placeholder="Select recommended medical products..."
                            className="w-full super-select-modern"
                            value={formik.values.products}
                            onChange={(val) => formik.setFieldValue("products", val)}
                            filterOption={(input, option) =>
                                (option?.label ?? '').toLowerCase().includes(input.toLowerCase())
                            }
                            options={productState.map(p => ({
                                label: p.title,
                                value: p._id
                            }))}
                        />
                        <div className="p-4 rounded-2xl bg-emerald-50 border border-emerald-100 flex gap-3">
                            <ShieldCheck size={20} className="text-emerald-500 flex-shrink-0" />
                            <p className="text-[11px] text-emerald-800 font-bold leading-tight uppercase tracking-tight">
                                Products linked here will appear as "Pharmacist-Picked Options" on the frontend details page.
                            </p>
                        </div>
                    </div>
                </div>
            </div>

            <style>{`
                .super-select-modern .ant-select-selector {
                    border-radius: 20px !important;
                    background: #f8fafc !important;
                    border: 1px solid #f1f5f9 !important;
                    padding: 8px 16px !important;
                    min-height: 56px !important;
                }
                .super-select-modern .ant-select-selection-item {
                    background: #fff !important;
                    border-radius: 10px !important;
                    border: 1px solid #f1f5f9 !important;
                    font-weight: 800 !important;
                    font-size: 11px !important;
                    text-transform: uppercase !important;
                    color: #475569 !important;
                    margin: 4px !important;
                }
            `}</style>
        </div>
    );
};

export default AddHealthAdvice;
